  // About page
  "about.since": { tr: "1999'dan beri", en: "Since 1999" },
  "about.heroTitle1": { tr: "Zorlu Digital Plaza", en: "Zorlu Digital Plaza" },
  "about.heroTitle2": { tr: "Zorlu Digital Trade & Services Ltd.", en: "Zorlu Digital Trade & Services Ltd." },
  "about.heroSubtitle": { tr: "26 Yıllık Güven - Teknoloji - Hizmet", en: "26 Years of Trust - Technology - Service" },
  "about.stat.customers": { tr: "Mutlu Müşteri", en: "Happy Customers" },
  "about.stat.years": { tr: "Yıllık Deneyim", en: "Years of Experience" },
