  "about.stat.products": { tr: "Binlerce Satılan Ürün", en: "Thousands of Products Sold" },
  "about.intro.title": { tr: "Hakkımızda", en: "About Us" },
  "about.intro.p1": { tr: "Zorlu Digital Plaza, Kuzey Kıbrıs'ta teknoloji perakendeciliği, elektronik ürün dağıtımı ve kurumsal teknoloji çözümleri alanında faaliyet gösteren Zorlu Digital Trade & Services Ltd. bünyesinde hizmet veren güçlü bir teknoloji platformudur.", en: "Zorlu Digital Plaza is a powerful technology platform operating under Zorlu Digital Trade & Services Ltd., active in technology retail, electronic product distribution and corporate technology solutions in Northern Cyprus." },
  "about.intro.p2": { tr: "1999 yılından bu yana teknoloji sektöründe faaliyet gösteren şirketimiz; 26 yılı aşkın deneyimi, dünya markalarıyla kurduğu güçlü iş birlikleri ve müşteri memnuniyetini merkeze alan hizmet anlayışı ile Kuzey Kıbrıs'ın güvenilir teknoloji merkezlerinden biri haline gelmiştir.", en: "Operating in the technology sector since 1999, our company has become one of the trusted technology centers of Northern Cyprus with over 26 years of experience, strong partnerships with world brands and a service approach centered on customer satisfaction." },
  "about.intro.p3": { tr: "Zorlu Digital Plaza yalnızca bir elektronik mağazası değildir. Biz, teknolojiyi günlük yaşamın konforu ile buluşturan, müşterilerine doğru ürünü doğru hizmet ile sunmayı amaçlayan modern bir teknoloji ekosistemiyiz.", en: "Zorlu Digital Plaza is not just an electronics store. We are a modern technology ecosystem that brings technology together with the comfort of daily life, aiming to offer the right product with the right service to our customers." },
  "about.why.title": { tr: "Neden Zorlu Digital Plaza", en: "Why Zorlu Digital Plaza" },
  "about.why.desc": { tr: "Teknoloji alışverişinde güven, kalite ve doğru hizmet büyük önem taşır. Zorlu Digital Plaza olarak müşterilerimize yalnızca ürün değil, bütüncül bir teknoloji deneyimi sunuyoruz.", en: "Trust, quality and the right service are crucial in technology shopping. As Zorlu Digital Plaza, we offer our customers not just products, but a holistic technology experience." },
  "about.why.subtitle": { tr: "Bizi Farklı Kılan Özellikler", en: "What Makes Us Different" },
  "about.why.f1": { tr: "26 yıllık sektör deneyimi", en: "26 years of industry experience" },
  "about.why.f2": { tr: "Dünya markalarıyla güçlü iş birlikleri", en: "Strong partnerships with world brands" },
  "about.why.f3": { tr: "Profesyonel satış danışmanlığı", en: "Professional sales consultancy" },
  "about.why.f4": { tr: "Satış sonrası teknik servis desteği", en: "After-sales technical service support" },
  "about.why.f5": { tr: "Hızlı teslimat ve kurulum hizmeti", en: "Fast delivery and installation service" },
  "about.why.f6": { tr: "Güvenilir alışveriş deneyimi", en: "Reliable shopping experience" },
  "about.why.goal": { tr: "Zorlu Digital Plaza olarak hedefimiz, müşterilerimize en doğru ürünü, en doğru hizmetle ve en doğru fiyat avantajıyla sunmaktır.", en: "Our goal as Zorlu Digital Plaza is to offer our customers the right product, with the right service and the right price advantage." },
  "about.brands.title": { tr: "Markalarımız", en: "Our Brands" },
  "about.brands.desc": { tr: "Zorlu Digital Plaza, dünya çapında güvenilir teknoloji markalarının ürünlerini müşterileriyle buluşturmaktadır.", en: "Zorlu Digital Plaza brings the products of world-renowned reliable technology brands to its customers." },
  "about.brands.global": { tr: "Çalıştığımız Global Markalar", en: "Global Brands We Work With" },
  "about.brands.services": { tr: "Bu markalara ait ürünler için müşterilerimize satış, kurulum, teknik servis ve yedek parça desteği sunulmaktadır.", en: "Sales, installation, technical service and spare parts support are provided to our customers for products of these brands." },
  "about.brands.mission": { tr: "Zorlu Digital Plaza, dünya markalarının en yeni teknolojilerini Kuzey Kıbrıs'taki müşterileriyle buluşturmayı hedeflemektedir.", en: "Zorlu Digital Plaza aims to bring the latest technologies of world brands to its customers in Northern Cyprus." },
  "about.service.title": { tr: "Teknik Servis", en: "Technical Service" },
  "about.service.desc": { tr: "Zorlu Digital Plaza, Kuzey Kıbrıs genelinde Samsung ve LG başta olmak üzere birçok elektronik ürün için profesyonel teknik servis hizmeti sunmaktadır.", en: "Zorlu Digital Plaza provides professional technical service for many electronic products, especially Samsung and LG, throughout Northern Cyprus." },
  "about.service.subtitle": { tr: "Teknik Servis Hizmetlerimiz", en: "Our Technical Services" },
  "about.service.s1": { tr: "Televizyon teknik servis", en: "Television technical service" },
  "about.service.s2": { tr: "Klima bakım ve onarım", en: "AC maintenance and repair" },
  "about.service.s3": { tr: "Beyaz eşya servis hizmetleri", en: "White goods service" },
  "about.service.s4": { tr: "Küçük ev aletleri servis hizmetleri", en: "Small appliance service" },
  "about.service.s5": { tr: "Yazılım güncelleme ve arıza tespiti", en: "Software update and fault detection" },
  "about.service.s6": { tr: "Orijinal yedek parça değişimi", en: "Original spare parts replacement" },
  "about.service.footer": { tr: "Uzman teknik servis ekibimiz, cihazlarınızın bakım ve onarım süreçlerini hızlı, güvenilir ve profesyonel şekilde yönetmektedir.", en: "Our expert technical service team manages the maintenance and repair processes of your devices quickly, reliably and professionally." },
  "about.b2b.title": { tr: "Kurumsal Satış", en: "Corporate Sales" },
  "about.b2b.desc": { tr: "Zorlu Digital Plaza, işletmeler ve kurumlar için B2B kurumsal teknoloji çözümleri sunmaktadır.", en: "Zorlu Digital Plaza offers B2B corporate technology solutions for businesses and institutions." },
  "about.b2b.f1": { tr: "Toplu alım avantajları", en: "Bulk purchase advantages" },
  "about.b2b.f2": { tr: "Özel fiyat teklifleri", en: "Special price offers" },
  "about.b2b.f3": { tr: "Proje bazlı teknoloji çözümleri", en: "Project-based technology solutions" },
  "about.b2b.f4": { tr: "Satış öncesi danışmanlık", en: "Pre-sales consultancy" },
  "about.b2b.f5": { tr: "Satış sonrası teknik destek", en: "After-sales technical support" },
  "about.b2b.productGroups": { tr: "Kurumsal Ürün Grupları", en: "Corporate Product Groups" },
  "about.b2b.footer": { tr: "Kurumsal müşterilerimiz için teknoloji tedarik süreçleri daha hızlı, daha verimli ve daha ekonomik hale getirilmektedir.", en: "Technology procurement processes are made faster, more efficient and more economical for our corporate customers." },
