  // B2B page
  "b2b.heroTitle": { tr: "Zorlu Digital Plaza ile Kurumsal Teknoloji Çözümleri", en: "Corporate Technology Solutions with Zorlu Digital Plaza" },
  "b2b.heroDesc1": { tr: "Zorlu Digital Plaza, Kuzey Kıbrıs'ta faaliyet gösteren şirketler, kurumlar ve işletmeler için profesyonel kurumsal teknoloji tedarik ve B2B satış çözümleri sunmaktadır.", en: "Zorlu Digital Plaza offers professional corporate technology procurement and B2B sales solutions for companies, institutions and businesses operating in Northern Cyprus." },
  "b2b.heroDesc2": { tr: "Şirketinizin ihtiyaç duyduğu televizyon, klima, beyaz eşya, ofis teknolojileri, elektronik cihazlar ve profesyonel ekipmanlara kurumsal fiyat avantajları ve toplu alım çözümleri ile kolayca ulaşabilirsiniz.", en: "You can easily access televisions, air conditioners, white goods, office technologies, electronic devices and professional equipment your company needs with corporate price advantages and bulk purchase solutions." },
  "b2b.procurement": { tr: "Kurumsal Elektronik Ürün Tedariki", en: "Corporate Electronic Product Procurement" },
  "b2b.procurementDesc": { tr: "Zorlu Digital Plaza, küçük işletmelerden büyük kurumsal firmalara kadar tüm işletmeler için geniş bir teknoloji ve elektronik ürün portföyü sunmaktadır. Şirketiniz için gerekli ürünleri toplu alım avantajları ve özel kurumsal fiyat teklifleri ile temin edebilirsiniz.", en: "Zorlu Digital Plaza offers a wide technology and electronics product portfolio for all businesses from small enterprises to large corporations. You can procure the products your company needs with bulk purchase advantages and special corporate price offers." },
  "b2b.brands": { tr: "Çalıştığımız Markalar", en: "Brands We Work With" },
  "b2b.brandsDesc": { tr: "Zorlu Digital Plaza, dünya çapında güvenilir teknoloji markalarının ürünlerini kurumsal müşterilerine sunmaktadır.", en: "Zorlu Digital Plaza offers products from globally trusted technology brands to its corporate customers." },
  "b2b.brandsNote": { tr: "Bu markalara ait ürünler için satış, kurulum, teknik servis ve satış sonrası destek hizmetleri sağlanmaktadır.", en: "Sales, installation, technical service and after-sales support services are provided for products of these brands." },
  "b2b.productGroups": { tr: "Ürün Gruplarımız", en: "Our Product Groups" },
  "b2b.productGroupsDesc": { tr: "Kurumsal müşterilerimiz için sunduğumuz ürün kategorileri:", en: "Product categories we offer for our corporate customers:" },
  "b2b.advantages": { tr: "B2B Kurumsal Satış Avantajları", en: "B2B Corporate Sales Advantages" },
  "b2b.advantagesDesc": { tr: "Zorlu Digital Plaza kurumsal satış hizmeti ile işletmeler birçok avantajdan yararlanabilir.", en: "Businesses can benefit from many advantages with Zorlu Digital Plaza corporate sales service." },
  "b2b.advantagesNote": { tr: "Uzman ekiplerimiz, işletmenizin ihtiyaçlarını analiz ederek en doğru teknoloji çözümlerini en uygun maliyetlerle sunar.", en: "Our expert teams analyze your business needs and offer the most suitable technology solutions at the best costs." },
  "b2b.customSolutions": { tr: "Kurumlara Özel Teknolojik Çözümler", en: "Custom Technology Solutions for Institutions" },
  "b2b.customSolutionsDesc": { tr: "Her işletmenin teknoloji ihtiyaçları farklıdır. Zorlu Digital Plaza, kurumsal müşterilerine ihtiyaçlarına uygun özel teknoloji çözümleri sunmaktadır.", en: "Every business has different technology needs. Zorlu Digital Plaza offers custom technology solutions tailored to its corporate customers' needs." },
  "b2b.customSolutionsNote": { tr: "Profesyonel ekiplerimiz, işletmenizin ihtiyaçlarını analiz ederek en verimli teknoloji altyapısını oluşturmanıza yardımcı olur.", en: "Our professional teams help you create the most efficient technology infrastructure by analyzing your business needs." },
  "b2b.sme": { tr: "KOBİ'ler İçin Teknoloji Çözümleri", en: "Technology Solutions for SMEs" },
  "b2b.smeDesc1": { tr: "Küçük ve orta ölçekli işletmelerin büyüme süreçlerinde doğru teknoloji yatırımları büyük önem taşır.", en: "The right technology investments are crucial in the growth process of small and medium-sized enterprises." },
  "b2b.smeDesc2": { tr: "Zorlu Digital Plaza, KOBİ'lere yönelik televizyon ve ekran çözümleri, ofis teknolojileri, güvenlik kamera sistemleri, klima ve iklimlendirme sistemleri, mutfak ve küçük ev aletleri gibi birçok teknolojik ürünü uygun fiyat ve kurumsal destek ile sunmaktadır.", en: "Zorlu Digital Plaza offers many technological products to SMEs such as television and screen solutions, office technologies, security camera systems, air conditioning systems, kitchen and small appliances at affordable prices with corporate support." },
  "b2b.enterprise": { tr: "Büyük Ölçekli Firmalara Özel Çözümler", en: "Solutions for Large Enterprises" },
  "b2b.enterpriseDesc1": { tr: "Kurumsal ölçek büyüdükçe teknoloji altyapısı da daha kapsamlı hale gelir.", en: "As corporate scale grows, technology infrastructure becomes more comprehensive." },
  "b2b.enterpriseDesc2": { tr: "Zorlu Digital Plaza, büyük ölçekli kurumlara otel ve turizm sektörü elektronik çözümleri, restoran ve kafe ekipmanları, toplantı ve konferans teknolojileri, klima ve iklimlendirme sistemleri, profesyonel ekran ve görüntü sistemleri gibi gelişmiş teknoloji çözümleri sunmaktadır.", en: "Zorlu Digital Plaza offers advanced technology solutions to large-scale institutions including hotel and tourism sector electronics, restaurant and cafe equipment, meeting and conference technologies, air conditioning systems, professional screen and display systems." },
  "b2b.process": { tr: "Kurumsal Satış Süreci", en: "Corporate Sales Process" },
  "b2b.processDesc": { tr: "Zorlu Digital Plaza kurumsal satış süreci profesyonel şekilde yönetilir.", en: "Zorlu Digital Plaza corporate sales process is managed professionally." },
  "b2b.processNote": { tr: "Bu süreç sayesinde işletmeler teknoloji yatırımlarını en doğru ve verimli şekilde planlayabilir.", en: "Thanks to this process, businesses can plan their technology investments in the most accurate and efficient way." },
  "b2b.finalTitle": { tr: "Zorlu Digital Plaza Kurumsal Avantajları", en: "Zorlu Digital Plaza Corporate Advantages" },
  "b2b.trust": { tr: "26 Yıllık Güven - Teknoloji - Hizmet", en: "26 Years of Trust - Technology - Service" },
  "b2b.footerDesc": { tr: "Zorlu Digital Plaza, Zorlu Digital Trade & Services Ltd. bünyesinde faaliyet göstermekte ve teknoloji perakendeciliği ile kurumsal teknoloji çözümleri alanında Kuzey Kıbrıs'ta güvenilir bir marka olarak hizmet vermektedir.", en: "Zorlu Digital Plaza operates under Zorlu Digital Trade & Services Ltd. and serves as a reliable brand in Northern Cyprus in technology retail and corporate technology solutions." },
  "b2b.contactTitle": { tr: "Kurumsal Satış İletişim", en: "Corporate Sales Contact" },
  "b2b.contactDesc": { tr: "Kurumsal satış ve toplu alım talepleriniz için bizimle iletişime geçebilirsiniz.", en: "You can contact us for corporate sales and bulk purchase requests." },
  "b2b.seoTitle": { tr: "Sık Aranan Kurumsal Hizmetler", en: "Frequently Searched Corporate Services" },

